#include <stdio.h>
#include <stdlib.h>
int main()
{
	char chess[8][8];
	int i,j,k;
	for(i=0;i<9;i++)
	{
		for(j=0;j<8;j++)
		{
			scanf("%c",&chess[i][j]);
		}
	}
	char variable[10]={'Q','R','B','N','P','q','r','b','n','p'};
	int value[10]={9,5,3,3,1,9,5,3,3,1};
	int black=0,white=0;
	for(i=0;i<9;i++)
	{
		for(j=0;j<8;j++)
		{
			for(k=0;k<10;k++)
			{
				if(chess[i][j]==variable[k])
				{
					if(k<5)
					{
						white+=value[k];	
					}
					else
					{
						black+=value[k];
					}
				}
			}
		}
	} 
	if(white>black)
		printf("White\n");
	else if(black>white)
		printf("Black\n");
	else 
		printf("Draw\n");
	return 0;
}

